fn _re_eclosure_s(
    re: *const Regex, cur: *std.ArrayListUnmanaged(_RegThread),
    vis: []bool, alloc: std.mem.Allocator,
    state: u32, saves: [_MAX_SAVE_SLOTS]usize, pos: usize, input: []const u8,
